'use client';
import { createClient } from '@/utils/supabase/client';
import { useEffect, useState } from 'react';
import Link from 'next/link';
import { Plus } from 'lucide-react';

export default function PedidosPage() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const supabase = createClient();

  useEffect(() => {
    async function fetchOrders() {
      const { data: { user } } = await supabase.auth.getUser();

      if (user) {
        const { data, error } = await supabase
          .from('orders')
          .select('*')
          .eq('distributor_id', user.id)
          .order('created_at', { ascending: false });

        if (data) setOrders(data);
      }
      setLoading(false);
    }
    fetchOrders();
  }, []);

  return (
    <div className="pedidos-container">
      <div className="page-header">
        <h1>Mis Pedidos</h1>
        <Link href="/dashboard/pedidos/nuevo" className="btn btn-primary btn-sm" style={{ display: 'inline-flex', alignItems: 'center', gap: '0.5rem', textDecoration: 'none' }}>
          <Plus size={18} />
          Nuevo Pedido
        </Link>
      </div>

      <div className="glass-panel" style={{ padding: '1.5rem' }}>
        {loading ? (
          <div className="text-center text-muted">Cargando pedidos...</div>
        ) : orders.length === 0 ? (
          <div className="empty-state">
            <p>No tienes pedidos activos.</p>
            <Link href="/dashboard/pedidos/nuevo" className="btn btn-outline-light btn-sm mt-4" style={{ display: 'inline-block', textDecoration: 'none' }}>Crear mi primer pedido</Link>
          </div>
        ) : (
          <table className="orders-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Fecha</th>
                <th>Estado</th>
                <th>Total</th>
                <th>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {orders.map((order) => (
                <tr key={order.id}>
                  <td>#{order.order_number}</td>
                  <td>{new Date(order.created_at).toLocaleDateString()}</td>
                  <td>
                    <span className={`status-badge ${order.status}`}>{order.status}</span>
                  </td>
                  <td>${order.total_amount}</td>
                  <td>
                    <Link href={`/dashboard/pedidos/${order.id}`} className="btn-link">Ver</Link>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <style jsx>{`
        .pedidos-container {
          max-width: 1200px;
          margin: 0 auto;
        }

        .page-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 2rem;
        }

        .page-header h1 {
          font-size: 1.75rem;
          color: white;
        }

        .empty-state {
          text-align: center;
          padding: 4rem 1rem;
          color: var(--color-text-muted);
        }

        .orders-table {
          width: 100%;
          border-collapse: collapse;
          color: white;
        }

        .orders-table th {
          text-align: left;
          padding: 1rem;
          border-bottom: 1px solid rgba(255,255,255,0.1);
          color: var(--color-text-muted);
          font-weight: 500;
          font-size: 0.9rem;
        }

        .orders-table td {
          padding: 1rem;
          border-bottom: 1px solid rgba(255,255,255,0.05);
          font-size: 0.95rem;
        }

        .status-badge {
          padding: 0.25rem 0.5rem;
          border-radius: 4px;
          font-size: 0.75rem;
          font-weight: 700;
          text-transform: uppercase;
        }
        
        .status-badge.pending { background: rgba(234, 179, 8, 0.2); color: #fbbf24; }
        .status-badge.processing { background: rgba(59, 130, 246, 0.2); color: #60a5fa; }
        .status-badge.shipped { background: rgba(34, 197, 94, 0.2); color: #4ade80; }

        .btn-link {
          background: none;
          border: none;
          color: var(--color-primary);
          cursor: pointer;
          font-size: 0.9rem;
        }
        
        .btn-link:hover {
          text-decoration: underline;
        }
      `}</style>
    </div>
  );
}
